const {BeforeStep, AfterStep, BeforeAll, AfterAll} = require('@cucumber/cucumber')
const {expect} = require('chai')

let counter = 1

BeforeStep(function() { 
  counter = counter + 1
})

AfterStep(function() {
  expect(counter).to.eql(2)
  counter = counter + 1
})

AfterAll(function() {
  expect(counter).to.eql(3)
})

const { BeforeStep } = require('@cucumber/cucumber')
BeforeStep({tags: "@any-tag"}, function() {
  throw Error("Would fail if ran")
})

const { AfterStep } = require('@cucumber/cucumber')
AfterStep({tags: "@this-tag"}, function() {
  throw Error("Would fail if ran")
})

const { AfterStep, Status } = require('@cucumber/cucumber')

AfterStep(function({result}) {
  if (result.status === Status.PASSED) {
    return
  } else {
    throw Error("Result object did not get passed properly to AfterStep Hook.")
  }
})

const {BeforeStep, AfterStep, BeforeAll, AfterAll} = require('@cucumber/cucumber')
const {expect} = require('chai')

let counter = 1

BeforeStep(function() { 
  counter = counter + 1
})

AfterStep(function() {
  expect(counter).to.eql(2)
  counter = counter + 1
})

AfterAll(function() {
  expect(counter).to.eql(3)
})

const { BeforeStep } = require('@cucumber/cucumber')
BeforeStep({tags: "@any-tag"}, function() {
  throw Error("Would fail if ran")
})

const { AfterStep } = require('@cucumber/cucumber')
AfterStep({tags: "@this-tag"}, function() {
  throw Error("Would fail if ran")
})

const { AfterStep, Status } = require('@cucumber/cucumber')

AfterStep(function({result}) {
  if (result.status === Status.PASSED) {
    return
  } else {
    throw Error("Result object did not get passed properly to AfterStep Hook.")
  }
})

const {setWorldConstructor, Then, When} = require('@cucumber/cucumber')
const assert = require('assert')

setWorldConstructor(function () {
  this.count = 0
})

When(/^I call a watched step$/, function() {
  this.count += 1
})

Then(/^the watched step should have been called (\d+) times?$/, function(count){
  assert.equal(this.count, parseInt(count))
})

const {setWorldConstructor, Then, When} = require('@cucumber/cucumber')
const assert = require('assert')

setWorldConstructor(function () {
  this.parameters = {}
})

When(/^I call a step with "([^"]*)"$/, function(arg) {
  this.parameters['1'] = arg
})

When(/^I call a step with "([^"]*)", "([^"]*)" and "([^"]*)"$/, function(arg1, arg2, arg3) {
  this.parameters['1'] = arg1
  this.parameters['2'] = arg2
  this.parameters['3'] = arg3
})

Then(/^the (\d+)(?:st|nd|rd) received parameter should be "([^"]*)"$/, function(index, arg){
  assert.equal(this.parameters[index], arg)
})

